final:
module top_module(
    input clk,
    input en,
    input data,
    output gated_clk
);reg ungated_clk_reg;

    always @(posedge clk) begin
        if (en && data) begin
            ungated_clk_reg <= 1'b1;
        end else begin
            ungated_clk_reg <= 1'b0;
        end
    end

    assign gated_clk = ungated_clk_reg;

endmodule
